parameters.jsCode:
// Calculate similarity scores and prepare data
const searchResults = $input.all();
let similarities = [];
let maxSimilarity = 0;

if (searchResults && searchResults[0] && searchResults[0].json.documents) {
  const docs = searchResults[0].json.documents;

  similarities = docs.map(doc => ({
    content: doc.content || '',
    similarity_score: doc.score || 0
  })).filter(doc => doc.similarity_score >= 0.75)
    .sort((a, b) => b.similarity_score - a.similarity_score);

  maxSimilarity = similarities.length > 0 ? similarities[0].similarity_score : 0;
}

const emailData = $node['Extract Email Metadata'].json;

return {
  json: {
    ...emailData,
    similar_replies: similarities,
    max_similarity_score: maxSimilarity,
    similarity_count: similarities.length
  }
};

